// Валидация + нормализация формы. Поддерживает оба тарифа: free и premium.
const input = $input.first().json;
const body = input.body || input;

const {
  tier = 'free',
  city = 'krym',
  days = 7,
  composition = 'couple',
  transport = 'car',
  budget = 5000,
  topic = 'obzor',
  notes = '',
  email = '',
  // premium-only поля (для free игнорируются)
  comfort = '',
  allergies = '',
  arrivalDate = '',
  departureDate = '',
  arrivalPoint = ''
} = body;

if (!email || !String(email).includes('@')) {
  throw new Error('Невалидный email: ' + email);
}

const tierNorm = tier === 'premium' ? 'premium' : 'free';
const nDays = Math.max(1, Math.min(21, Number(days) || 7));

const cityNames = {
  krym: 'Весь Крым',
  yalta: 'Ялта и Южный берег Крыма',
  sevastopol: 'Севастополь',
  bahchisaray: 'Бахчисарай',
  feodosiya: 'Феодосия и Коктебель',
  evpatoriya: 'Евпатория и западный Крым'
};
const compNames = {
  couple: 'пара',
  'family-kids': 'семья с детьми',
  friends: 'друзья',
  solo: 'один',
  parents: 'с родителями'
};
const transportNames = {
  car: 'на автомобиле',
  public: 'общественный транспорт (троллейбус №52, маршрутки, автобусы)',
  taxi: 'такси и трансферы',
  mixed: 'комбинированно (поезд/самолёт + такси)'
};
const topicNames = {
  obzor: 'обзорный — главные места',
  'more-plyazh': 'море и пляжи',
  gory: 'горы и треккинг',
  istoriya: 'история и архитектура',
  gastro: 'гастро и виноделие',
  's-detmi': 'с детьми',
  aktiv: 'активный отдых'
};
const comfortNames = {
  hostel: 'хостел / гестхаус',
  econom: 'эконом 3*',
  comfort: 'комфорт 4*',
  premium: 'премиум 5*+ / бутик'
};
const arrivalPointNames = {
  simferopol: 'аэропорт Симферополь',
  anapa: 'аэропорт Анапа',
  krasnodar: 'аэропорт Краснодар',
  'own-car': 'на машине через Крымский мост',
  train: 'поезд (Симферополь / Севастополь)'
};
const budgetNum = Number(budget) || 5000;
let budgetText;
if (budgetNum < 1500) budgetText = 'бюджетный (до 1 500 ₽ на чел/день)';
else if (budgetNum < 3000) budgetText = 'эконом (1 500–3 000 ₽ на чел/день)';
else if (budgetNum < 5000) budgetText = 'средний (3 000–5 000 ₽ на чел/день)';
else if (budgetNum < 10000) budgetText = 'комфорт (5 000–10 000 ₽ на чел/день)';
else budgetText = 'премиум (от 10 000 ₽ на чел/день)';

return [{
  json: {
    tier: tierNorm,
    city: String(city),
    cityName: cityNames[city] || cityNames.krym,
    days: nDays,
    composition: String(composition),
    compName: compNames[composition] || 'пара',
    transport: String(transport),
    transportName: transportNames[transport] || transportNames.car,
    budget: budgetNum,
    budgetText,
    topic: String(topic),
    topicName: topicNames[topic] || topicNames.obzor,
    notes: String(notes).slice(0, 500),
    email: String(email).trim().toLowerCase(),
    // premium-only
    comfort: tierNorm === 'premium' ? String(comfort) : '',
    comfortName: tierNorm === 'premium' ? (comfortNames[comfort] || '') : '',
    allergies: tierNorm === 'premium' ? String(allergies).slice(0, 300) : '',
    arrivalDate: tierNorm === 'premium' ? String(arrivalDate) : '',
    departureDate: tierNorm === 'premium' ? String(departureDate) : '',
    arrivalPoint: tierNorm === 'premium' ? String(arrivalPoint) : '',
    arrivalPointName: tierNorm === 'premium' ? (arrivalPointNames[arrivalPoint] || '') : ''
  }
}];

// Tier-aware промпт для OpenAI. Использует каталог проверенных мест.
// Для free — компактный; для premium — расширенный с адресами, ресторанами, чек-листом и планом Б.
const m = $('Validate & Normalize').first().json;
const catalog = $('Fetch Attractions Catalog').first().json;

// Каталог может прийти как массив или как объект с ключом data — нормализуем
const catalogArr = Array.isArray(catalog) ? catalog : (Array.isArray(catalog.data) ? catalog.data : []);

// Фильтр по региону: пользователь выбирает город — берём места только из соответствующего региона.
const cityToRegions = {
  krym: null, // весь Крым — все регионы
  yalta: ['Южный берег'],
  sevastopol: ['Севастополь', 'Южный берег'], // Севастополь + рядом
  bahchisaray: ['Центральный Крым', 'Севастополь'],
  feodosiya: ['Восточный Крым'],
  evpatoriya: ['Западный Крым']
};
const allowedRegions = cityToRegions[m.city];
let filtered = allowedRegions ? catalogArr.filter(p => allowedRegions.includes(p.region)) : catalogArr;

// Если фильтр оставил <10 мест — добавим премиум-узлы из соседних регионов
if (filtered.length < 10 && allowedRegions) {
  const obyazatelno = catalogArr.filter(p => p.tags && p.tags.includes('обязательно') && !filtered.includes(p));
  filtered = filtered.concat(obyazatelno.slice(0, 8));
}

// Если выбран фокус — поднимаем релевантные теги
const topicTags = {
  'more-plyazh': ['море', 'пляж'],
  'gory': ['трекинг', 'горы', 'природа'],
  'istoriya': ['история', 'архитектура', 'археология'],
  'gastro': ['вино', 'винодельня'],
  's-detmi': ['с детьми'],
  'aktiv': ['активные', 'трекинг', 'адреналин']
};
const preferredTags = topicTags[m.topic] || [];

// Сортируем: сначала с релевантными тегами, потом обязательно, потом остальные
filtered.sort((a, b) => {
  const aTags = a.tags || [];
  const bTags = b.tags || [];
  const aPref = preferredTags.some(t => aTags.includes(t)) ? 1 : 0;
  const bPref = preferredTags.some(t => bTags.includes(t)) ? 1 : 0;
  if (aPref !== bPref) return bPref - aPref;
  const aMust = aTags.includes('обязательно') ? 1 : 0;
  const bMust = bTags.includes('обязательно') ? 1 : 0;
  return bMust - aMust;
});

// Форматируем компактный каталог для промпта
const catalogText = filtered.map((p, i) => {
  const parts = [`${i+1}. ${p.name} — ${p.city}`];
  if (p.address) parts.push(`адрес: ${p.address}`);
  if (p.hours && p.hours.length < 80) parts.push(`часы: ${p.hours}`);
  else if (p.hours) parts.push(`часы: ${p.hours.split(',')[0]}`);
  if (p.price_avg) parts.push(`цена: ${p.price_avg}`);
  if (p.duration_min) parts.push(`длит: ${p.duration_min} мин`);
  const flagBits = [];
  if (p.rainy_ok) flagBits.push('в дождь ОК');
  if (p.kid_friendly) flagBits.push('с детьми ОК');
  if (flagBits.length) parts.push(flagBits.join(', '));
  const tagStr = (p.tags || []).filter(t => t !== 'обязательно' && t !== 'бесплатно').slice(0, 4).join(', ');
  if (tagStr) parts.push(`теги: ${tagStr}`);
  return parts.join(' | ') + (p.description ? `\n   ${p.description}` : '');
}).join('\n');

const baseHeader = `Составь маршрут по Крыму на ${m.days} дней.\n\n**Параметры**:\n- Регион: ${m.cityName}\n- Длительность: ${m.days} дней\n- Состав: ${m.compName}\n- Транспорт: ${m.transportName}\n- Бюджет: ${m.budgetText}\n- Главный интерес: ${m.topicName}\n- Особые пожелания: ${m.notes || 'нет'}`;

const catalogInstruction = `\n\n**Каталог проверенных мест (${filtered.length} точек) — используй ТОЛЬКО их**:\n${catalogText}\n\n**ВАЖНО**: НЕ ВЫДУМЫВАЙ новых мест, ресторанов или адресов. Все точки маршрута должны быть из каталога выше. Если в каталоге нет нужной категории — выбирай ближайшую по смыслу. Адреса бери ТОЧНО из каталога.`;

let userPrompt;
let systemPrompt;
let maxTokens;

if (m.tier === 'premium') {
  const premiumExtras = [
    m.comfortName ? `- Уровень проживания: ${m.comfortName}` : null,
    m.arrivalPointName ? `- Прибытие через: ${m.arrivalPointName}` : null,
    m.arrivalDate ? `- Дата прибытия: ${m.arrivalDate}` : null,
    m.departureDate ? `- Дата отъезда: ${m.departureDate}` : null,
    m.allergies ? `- Аллергии и ограничения: ${m.allergies}` : null
  ].filter(Boolean).join('\n');

  const itemsPerDay = m.composition === 'family-kids' ? '5-6' : '6-8';

  userPrompt = `${baseHeader}\n${premiumExtras ? '\n**Дополнительно (премиум)**:\n' + premiumExtras + '\n' : ''}${catalogInstruction}\n\n**Премиум-требования**:\n1. Каждый день — ${itemsPerDay} точек с тайм-слотами (09:00, 11:30, 13:30, 16:00, 18:30, 20:30…).\n2. У каждой точки указывай адрес ТОЧНО из каталога и время в пути от предыдущей точки.\n3. Минимум 2 ресторана/кафе в день — БЕРИ ИЗ КАТАЛОГА если они там есть (тип winery/entertainment); если нет — пропусти ресторан, не выдумывай.\n4. Учитывай погодные альтернативы: если у точки rainy_ok=false и день может быть дождливым, предлагай запасной вариант.\n5. Чек-лист «что взять в дорогу» (5–8 пунктов).\n6. Один день — главный (топ-впечатление); один день — расслабленный.\n7. Если получится — кольцевой маршрут (не возвращаться в одну точку дважды).\n\nВерни строго JSON по схеме:\n{\n  \"title\": \"Краткое название маршрута\",\n  \"summary\": \"1-2 предложения\",\n  \"days\": [\n    {\n      \"day\": 1,\n      \"title\": \"Город/тема дня\",\n      \"city\": \"Основной город\",\n      \"items\": [\n        { \"time\": \"09:00\", \"place\": \"Название из каталога\", \"address\": \"адрес из каталога\", \"travel\": \"15 мин на машине\", \"note\": \"что посмотреть\" }\n      ],\n      \"restaurants\": [\n        { \"name\": \"Название\", \"cuisine\": \"крымско-татарская\", \"price\": \"средний чек 1500₽\", \"why\": \"чебуреки и плов\" }\n      ],\n      \"rainy_alternative\": \"что делать если дождь — БЕРИ только rainy_ok места\"\n    }\n  ],\n  \"checklist\": [\"кроссовки для троп\", \"крем SPF 50\", \"...\"],\n  \"tips\": [\"совет 1\", \"совет 2\"],\n  \"budget_estimate\": \"общая оценка бюджета\"\n}`;

  systemPrompt = `Ты — опытный гид по Крыму с глубоким знанием Южного берега, Севастополя, горного Крыма. Составляешь детальные маршруты с обязательным указанием реальных адресов, времени в пути и проверенных ресторанов. КРИТИЧЕСКИ ВАЖНО: используй ТОЛЬКО места из приложенного каталога. НЕ ВЫДУМЫВАЙ адреса, координаты, рестораны или достопримечательности — берёшь их из каталога. Если в каталоге не хватает мест для дня — лучше предложи поменьше точек, чем выдумай. Отвечай ТОЛЬКО валидным JSON без markdown-обёртки.`;

  maxTokens = 4000;
} else {
  // FREE — компактный план
  const itemsPerDay = m.composition === 'family-kids' ? '4-5' : '4-6';

  userPrompt = `${baseHeader}${catalogInstruction}\n\n**Требования**:\n1. Каждый день — ${itemsPerDay} точек с временем (09:00, 11:30, 15:00, 18:00).\n2. Названия точек ТОЧНО из каталога.\n3. 3-5 общих советов (когда ехать, что взять, что попробовать из еды).\n4. Оцени общий бюджет на ${m.compName} (${m.days} дней).\n\nВерни строго JSON по схеме:\n{\n  \"title\": \"Краткое название маршрута\",\n  \"summary\": \"1-2 предложения\",\n  \"days\": [\n    {\n      \"day\": 1,\n      \"title\": \"Город/тема дня\",\n      \"city\": \"Основной город\",\n      \"items\": [\"09:00 — Точка (название из каталога)\", \"...\"]\n    }\n  ],\n  \"tips\": [\"совет 1\", \"совет 2\"],\n  \"budget_estimate\": \"общая оценка бюджета\"\n}`;

  systemPrompt = `Ты — опытный гид по Крыму. Составляешь короткий, чёткий маршрут. КРИТИЧЕСКИ ВАЖНО: используй ТОЛЬКО места из приложенного каталога. НЕ ВЫДУМЫВАЙ названия, адреса, рестораны. Если в каталоге не хватает мест — лучше меньше точек, чем выдумка. Отвечай ТОЛЬКО валидным JSON без markdown-обёртки.`;

  maxTokens = 2800;
}

return [{
  json: {
    ...m,
    systemPrompt,
    userPrompt,
    maxTokens,
    catalogSize: filtered.length
  }
}];

// Парсим ответ OpenAI и рендерим красивый HTML email.
// Tier-aware: для premium показываем рестораны, план Б, чек-лист и адреса.
const openaiRaw = $input.first().json;
const content = openaiRaw.choices?.[0]?.message?.content || '{}';

let plan;
try {
  plan = JSON.parse(content);
} catch (e) {
  const m = content.match(/\{[\s\S]+\}/);
  plan = m ? JSON.parse(m[0]) : { title: 'Ошибка', summary: 'Не удалось распарсить ответ AI', days: [], tips: [], budget_estimate: '' };
}

const meta = $('Validate & Normalize').first().json;
const isPremium = meta.tier === 'premium';

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));

// Item рендер. Поддерживает строковый формат (free) и объектный (premium).
function renderItem(item) {
  if (typeof item === 'string') {
    return `<li style="padding: 6px 0 6px 18px; position: relative;"><span style="position:absolute; left:0; color:#7A1F2B;">·</span>${esc(item)}</li>`;
  }
  const time = esc(item.time || '');
  const place = esc(item.place || '');
  const meta2 = [item.address, item.travel].filter(Boolean).map(esc).join(' · ');
  const metaLine = meta2 ? `<div style=\"font-size:13px; color:#6b6b6b; margin-top:2px;\">${meta2}</div>` : '';
  const note = item.note ? `<div style=\"font-size:14px; color:#2a2a2a; margin-top:4px;\">${esc(item.note)}</div>` : '';
  return `<li style="padding: 10px 0 10px 18px; position: relative; border-top: 1px dashed #e6e2d8;">
    <span style="position:absolute; left:0; color:#7A1F2B;">·</span>
    <strong style="font-family: Georgia, serif;">${time ? time + ' — ' : ''}${place}</strong>${metaLine}${note}
  </li>`;
}

const dayBlocks = (plan.days || []).map((d) => {
  const items = (d.items || []).map(renderItem).join('\n');
  let extras = '';
  if (isPremium) {
    if (d.restaurants && d.restaurants.length) {
      const restList = d.restaurants.map(r => `<li style=\"padding:6px 0;\"><strong>${esc(r.name)}</strong>${r.cuisine ? ' — ' + esc(r.cuisine) : ''}${r.price ? ' · ' + esc(r.price) : ''}${r.why ? '<div style=\"font-size:13px; color:#6b6b6b; margin-top:2px;\">' + esc(r.why) + '</div>' : ''}</li>`).join('\n');
      extras += `<div style=\"margin: 18px 0 8px;\"><div style=\"font-family: Inter, sans-serif; font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; color: #7A1F2B; margin-bottom: 8px;\">Рестораны и кафе</div><ul style=\"list-style:none; padding:0; margin:0;\">${restList}</ul></div>`;
    }
    if (d.rainy_alternative) {
      extras += `<div style=\"margin: 16px 0; padding: 12px; background: #fbf6ed; border-left: 3px solid #7A1F2B;\"><div style=\"font-family: Inter, sans-serif; font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; color: #7A1F2B; margin-bottom: 6px;\">План Б на дождь</div><div style=\"font-size:14px; color:#2a2a2a;\">${esc(d.rainy_alternative)}</div></div>`;
    }
  }
  return `<div style=\"margin: 28px 0; padding: 22px; background: #fff; border: 1px solid #e6e2d8;\">
    <div style=\"display:flex; align-items:baseline; gap:14px; margin-bottom:10px;\">
      <span style=\"font-family: Georgia, serif; font-size: 28px; color: #7A1F2B; font-style: italic;\">${d.day || '?'}</span>
      <h3 style=\"margin:0; font-family: Georgia, serif; font-size: 20px; color: #1A2845;\">${esc(d.title || d.city || 'День')}</h3>
    </div>
    <ul style=\"list-style:none; padding:0; margin:0;\">${items}</ul>
    ${extras}
  </div>`;
}).join('\n');

const tipsBlock = (plan.tips && plan.tips.length) ? `<div style=\"margin: 24px 0; padding: 18px; background: #fbf6ed;\"><div style=\"font-family: Inter, sans-serif; font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; color: #7A1F2B; margin-bottom: 10px;\">Советы</div><ul style=\"margin:0; padding-left: 20px;\">${plan.tips.map(t => `<li style=\"padding:4px 0;\">${esc(t)}</li>`).join('')}</ul></div>` : '';

const checklistBlock = (isPremium && plan.checklist && plan.checklist.length) ? `<div style=\"margin: 24px 0; padding: 18px; background: #f6f3ed; border-left: 3px solid #1A2845;\"><div style=\"font-family: Inter, sans-serif; font-size: 11px; letter-spacing: 0.15em; text-transform: uppercase; color: #1A2845; margin-bottom: 10px;\">Чек-лист в дорогу</div><ul style=\"margin:0; padding-left: 20px;\">${plan.checklist.map(t => `<li style=\"padding:4px 0;\">${esc(t)}</li>`).join('')}</ul></div>` : '';

const budgetBlock = plan.budget_estimate ? `<p style=\"margin: 16px 0; font-style: italic; color: #6b6b6b;\">Бюджет: ${esc(plan.budget_estimate)}</p>` : '';

const tierBadge = isPremium ? `<div style=\"display:inline-block; font-family: Inter, sans-serif; font-size: 10px; letter-spacing: 0.18em; text-transform: uppercase; color: #fff; background: #7A1F2B; padding: 4px 10px; margin-bottom: 8px;\">Премиум · бесплатно в бета-периоде</div>` : '';

const html = `<!DOCTYPE html>
<html><head><meta charset=\"utf-8\"></head>
<body style=\"margin:0; padding: 0; background: #faf8f3; font-family: -apple-system, Inter, sans-serif; color: #1a1a1a; line-height: 1.5;\">
  <div style=\"max-width: 640px; margin: 0 auto; padding: 32px 24px;\">
    ${tierBadge}
    <h1 style=\"font-family: Georgia, serif; font-size: 36px; font-style: italic; color: #1A2845; margin: 0 0 10px;\">${esc(plan.title || 'Ваш маршрут по Крыму')}</h1>
    <p style=\"font-size: 16px; color: #444; margin: 0 0 6px;\">${esc(plan.summary || '')}</p>
    ${budgetBlock}
    ${dayBlocks}
    ${tipsBlock}
    ${checklistBlock}
    <hr style=\"border:none; border-top:1px solid #ddd; margin: 32px 0 18px;\">
    <p style=\"font-size: 13px; color: #888;\">План сгенерирован специально для вас — <a href=\"https://welcomecrimea.ru/\" style=\"color:#7A1F2B;\">welcomecrimea.ru</a></p>
  </div>
</body></html>`;

const subject = isPremium ? `Премиум-маршрут по Крыму на ${meta.days} дней` : `Ваш маршрут по Крыму на ${meta.days} дней`;

return [{ json: { html, subject, plan } }];
